1	import { getCircuitBreaker } from './hardening';
2	
3	export type ProviderName = 'vercel-gateway' | 'openai-direct' | 'xai-direct' | '-flash';
4	
5	export type ProviderAttempt = {
6	  name: ProviderName;
7	  status: 'failed' | 'selected';
8	  error?: string;
9	};
10	
11	export type ProviderHealthSnapshot = {
12	  gateway: {
13	    configured: boolean;
14	    available: boolean;
15	    reason: string | null;
16	    url: string;
17	    authSource: string | null;
18	  };
19	  openai: {
20	    configured: boolean;
21	    available: boolean;
22	    reason: string | null;
23	  };
24	  xai: {
25	    configured: boolean;
26	    available: boolean;
27	    reason: string | null;
28	  };
29	  : {
30	    configured: boolean;
31	    available: boolean;
32	    reason: string | null;
33	    keysConfigured: number;
34	  };
35	  preferredOrder: ProviderName[];
36	};
37	
38	export const DEFAULT_PROVIDER_ORDER: ProviderName[] = [
39	  'vercel-gateway',
40	  'xai-direct',
41	  '-flash',
42	  'openai-direct',
43	];
44	
45	const _KEYS = [
46	  process.env._API_KEY_4,
47	  process.env._API_KEY_2,
48	  process.env._API_KEY,
49	].filter(Boolean) as string[];
50	
51	export function resolveGatewayAuth(): { key: string | null; source: string | null } {
52	  if (process.env.AI_GATEWAY_API_KEY) {
53	    return { key: process.env.AI_GATEWAY_API_KEY, source: 'AI_GATEWAY_API_KEY' };
54	  }
55	
56	  if (process.env.VERCEL_AI_GATEWAY_KEY) {
57	    return { key: process.env.VERCEL_AI_GATEWAY_KEY, source: 'VERCEL_AI_GATEWAY_KEY' };
58	  }
59	
60	  if (process.env.VERCEL_OIDC_TOKEN) {
61	    return { key: process.env.VERCEL_OIDC_TOKEN, source: 'VERCEL_OIDC_TOKEN' };
62	  }
63	
64	  return { key: null, source: null };
65	}
66	
67	export function getProviderHealthSnapshot(): ProviderHealthSnapshot {
68	  const gatewayAuth = resolveGatewayAuth();
69	  const gatewayConfigured = Boolean(gatewayAuth.key);
70	  const openaiConfigured = Boolean(process.env.OPENAI_API_KEY);
71	  const xaiConfigured = Boolean(process.env.XAI_API_KEY);
72	  const Configured = _KEYS.length > 0;
73	
74	  return {
75	    gateway: {
76	      configured: gatewayConfigured,
77	      available: gatewayConfigured,
78	      reason: gatewayConfigured ? null : 'missing gateway auth',
79	      url: 'https://ai-gateway.vercel.sh/v1',
80	      authSource: gatewayAuth.source,
81	    },
82	    openai: {
83	      configured: openaiConfigured,
84	      available: openaiConfigured,
85	      reason: openaiConfigured ? null : 'missing OpenAI key',
86	    },
87	    xai: {
88	      configured: xaiConfigured,
89	      available: xaiConfigured,
90	      reason: xaiConfigured ? null : 'missing xAI key',
91	    },
92	    : {
93	      configured: Configured,
94	      available: Configured,
95	      reason: Configured ? null : 'missing  key(s)',
96	      keysConfigured: _KEYS.length,
97	    },
98	    preferredOrder: DEFAULT_PROVIDER_ORDER,
99	  };
100	}
101	
102	export function getProviderOrder(): ProviderName[] {
103	  return DEFAULT_PROVIDER_ORDER;
104	}
105	
106	export function serializeProviderHealth(snapshot: ProviderHealthSnapshot): string {
107	  return JSON.stringify(snapshot);
108	}
109	
110	export async function selectStreamingProvider(
111	  providers: Array<{ name: ProviderName; fn: () => Promise<ReadableStream> }>,
112	  encoder: TextEncoder,
113	  decoder: TextDecoder,
114	): Promise<{
115	  provider: ProviderName;
116	  stream: ReadableStream;
117	  attempts: ProviderAttempt[];
118	}> {
119	  let lastErr: unknown;
120	  const attempts: ProviderAttempt[] = [];
121	
122	  for (const p of providers) {
123	    // Skip providers whose circuit breaker is open (#V5)
