'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
  status?: 'streaming' | 'done' | 'error';
}

export interface Conversation {
  id: string;
  title: string;
  messages: Message[];
  createdAt: number;
}

export interface SystemState {
  provider: string;
  model: string;
  status: 'online' | 'degraded' | 'offline';
  memoryEntries: number;
  mode: 'public' | 'operator';
  uptime?: string;
}

export interface TelemetryEntry {
  id: string;
  timestamp: number;
  type: string;
  label: string;
  value: string | number;
}

function uid(): string {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

function deriveTitle(text: string): string {
  return text.slice(0, 40) + (text.length > 40 ? '…' : '');
}

const DEFAULT_SYSTEM_STATE: SystemState = {
  provider: 'OmegA',
  model: 'sovereign',
  status: 'online',
  memoryEntries: 0,
  mode: 'public',
};

export function useOmegaChat() {
  const [conversations, setConversations] = useState<Conversation[]>(() => {
    const first: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
    return [first];
  });
  const [activeConvoId, setActiveConvoId] = useState<string>(() => '');
  const [isStreaming, setIsStreaming] = useState(false);
  const [systemState, setSystemState] = useState<SystemState>(DEFAULT_SYSTEM_STATE);
  const [telemetry, setTelemetry] = useState<TelemetryEntry[]>([]);
  const abortRef = useRef<AbortController | null>(null);

  // init activeConvoId from first conversation
  useEffect(() => {
    setActiveConvoId(prev => prev || conversations[0]?.id || '');
  }, []);

  const activeConvo = conversations.find(c => c.id === activeConvoId);

  const addTelemetry = useCallback((type: string, label: string, value: string | number) => {
    const entry: TelemetryEntry = { id: uid(), timestamp: Date.now(), type, label, value };
    setTelemetry(prev => [entry, ...prev].slice(0, 100));
  }, []);

  // Poll runtime status every 30s
  useEffect(() => {
    const poll = async () => {
      try {
        const res = await fetch('/api/runtime-status');
        if (!res.ok) return;
        const data = await res.json();
        setSystemState(prev => ({
          ...prev,
          provider: data.posture?.provider ?? data.app ?? prev.provider,
          model: data.posture?.model ?? prev.model,
          status: data.posture?.status === 'degraded' ? 'degraded' : 'online',
          memoryEntries: data.posture?.memoryEntries ?? prev.memoryEntries,
          mode: data.posture?.mode ?? prev.mode,
          uptime: data.deployment?.vercelEnv ?? prev.uptime,
        }));
      } catch {
        setSystemState(prev => ({ ...prev, status: 'degraded' }));
      }
    };
    poll();
    const interval = setInterval(poll, 30_000);
    return () => clearInterval(interval);
  }, []);

  const newConversation = useCallback(() => {
    const convo: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
    setConversations(prev => [convo, ...prev]);
    setActiveConvoId(convo.id);
  }, []);

  const switchConversation = useCallback((id: string) => {
    setActiveConvoId(id);
  }, []);

  const deleteConversation = useCallback((id: string) => {
    setConversations(prev => {
      const next = prev.filter(c => c.id !== id);
      if (next.length === 0) {
        const fresh: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
        return [fresh];
      }
      return next;
    });
    setActiveConvoId(prev => {
      if (prev !== id) return prev;
      const remaining = conversations.filter(c => c.id !== id);
      return remaining[0]?.id ?? '';
    });
  }, [conversations]);

  const sendMessage = useCallback(async (text: string) => {
    if (!text.trim() || isStreaming) return;

    const userMsg: Message = { id: uid(), role: 'user', content: text.trim(), timestamp: Date.now(), status: 'done' };
    const assistantMsgId = uid();
    const assistantMsg: Message = { id: assistantMsgId, role: 'assistant', content: '', timestamp: Date.now(), status: 'streaming' };

    setConversations(prev => prev.map(c => {
      if (c.id !== activeConvoId) return c;
      const msgs = [...c.messages, userMsg, assistantMsg];
      return { ...c, messages: msgs, title: c.messages.length === 0 ? deriveTitle(text) : c.title };
    }));

    setIsStreaming(true);
    addTelemetry('send', 'user message', text.slice(0, 60));

    const ctrl = new AbortController();
    abortRef.current = ctrl;
    const start = Date.now();

    try {
      // Build history from current convo messages (exclude the assistant placeholder we just added)
      const history = (activeConvo?.messages ?? []).map(m => ({
        role: m.role === 'assistant' ? 'assistant' : 'user',
        content: m.content,
      }));

      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user: text.trim(), history }),
        signal: ctrl.signal,
      });

      if (!res.ok || !res.body) {
        throw new Error(`HTTP ${res.status}`);
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let accumulated = '';

      while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        const chunk = decoder.decode(value, { stream: true });
        // Skip SSE status lines
        if (chunk.startsWith('data: ')) continue;
        accumulated += chunk;
        const snap = accumulated;
        setConversations(prev => prev.map(c => {
          if (c.id !== activeConvoId) return c;
          return {
            ...c,
            messages: c.messages.map(m =>
              m.id === assistantMsgId ? { ...m, content: snap, status: 'streaming' as const } : m
            ),
          };
        }));
      }

      const elapsed = Date.now() - start;
      setConversations(prev => prev.map(c => {
        if (c.id !== activeConvoId) return c;
        return {
          ...c,
          messages: c.messages.map(m =>
            m.id === assistantMsgId ? { ...m, content: accumulated, status: 'done' as const } : m
          ),
        };
      }));

      addTelemetry('response', 'assistant reply', `${elapsed}ms · ${accumulated.length} chars`);
    } catch (err: unknown) {
      if (err instanceof Error && err.name === 'AbortError') return;
      setConversations(prev => prev.map(c => {
        if (c.id !== activeConvoId) return c;
        return {
          ...c,
          messages: c.messages.map(m =>
            m.id === assistantMsgId ? { ...m, content: 'Something went wrong. Please try again.', status: 'error' as const } : m
          ),
        };
      }));
      addTelemetry('error', 'stream failed', String(err));
    } finally {
      setIsStreaming(false);
    }
  }, [activeConvoId, activeConvo, isStreaming, addTelemetry]);

  const retryMessage = useCallback((messageId: string) => {
    const convo = conversations.find(c => c.id === activeConvoId);
    if (!convo) return;
    const idx = convo.messages.findIndex(m => m.id === messageId);
    if (idx < 0) return;
    // Find the user message before this assistant message
    const userMsg = convo.messages.slice(0, idx).reverse().find(m => m.role === 'user');
    if (!userMsg) return;
    // Remove failed message and resend
    setConversations(prev => prev.map(c => {
      if (c.id !== activeConvoId) return c;
      return { ...c, messages: c.messages.filter(m => m.id !== messageId) };
    }));
    sendMessage(userMsg.content);
  }, [conversations, activeConvoId, sendMessage]);

  return {
    conversations,
    activeConvoId,
    activeConvo,
    isStreaming,
    systemState,
    telemetry,
    sendMessage,
    retryMessage,
    newConversation,
    switchConversation,
    deleteConversation,
  };
}

