1	/**
2	 * OmegA Hardening Layer
3	 *
4	 * Centralised mitigations for the top-30 AI chat application failure modes
5	 * PLUS the voice/transport/infrastructure failure modes from the extended report.
6	 * Every defence maps to a numbered problem or report section.
7	 * Import and apply before any request reaches model or DB logic.
8	 *
9	 * Round 1 (text chat):
10	 *  #1  Scope enforcement — hard limits on what the endpoint will accept
11	 *  #4  Over-scripted / under-validated input — schema validation
12	 *  #5  Wordy / oversized input — character caps
13	 *  #7  Graceful error handling — never crash a stream silently
14	 *  #13 Context loss / long-chat drift — session history window cap
15	 *  #15 Edge cases & adversarial inputs — expanded injection patterns
16	 *  #16 Prompt injection & jailbreaks — deeper pattern set + rate gate
17	 *  #17 Data privacy — error sanitisation, no raw internals to client
18	 *  #21 Latency & scalability — lightweight in-memory rate limiter
19	 *  #22 Cost-driven collapse — token budget enforcement
20	 *  #23 Observability — structured request logging
21	 *  #24 Rushed launches — request schema validation at boundary
22	 *
23	 * Round 2 (voice/transport/infra):
24	 *  V1  Client/UX — mic permission error surface, TTS length cap, markdown strip
25	 *  V2  Transport — correlation IDs for full pipeline tracing
26	 *  V3  ASR — audio file validation (size, MIME type)
27	 *  V4  NLU/LLM — dialog loop detection
28	 *  V5  Tools/APIs — circuit breaker per provider, exponential backoff
29	 *  V6  TTS — markdown stripping before synthesis
30	 *  V7  Infrastructure — health check utilities, graceful degradation mode
31	 *  V8  Observability — correlation ID threading
32	 *  V9  Security — STT/TTS auth enforcement (key protection)
33	 *  #29 Mobile / accessibility — documented here, enforced in components
34	 */
35	
36	import { NextRequest } from 'next/server';
37	
38	// ── 1. Input Validation (#4, #5, #15, #24) ────────────────────────────────────
39	
40	export const LIMITS = {
41	  MAX_MESSAGE_CHARS: 4_000,
42	  MAX_HISTORY_TURNS: 30,       // each turn = 1 user + 1 assistant
43	  MAX_HISTORY_CHARS: 20_000,   // total characters across all history turns
44	  MAX_SESSION_ID_LEN: 64,
45	} as const;
46	
47	export interface ChatRequestSchema {
48	  user: string;
49	  history?: Array<{ role: 'user' | 'omega'; text: string }>;
50	  sessionId?: string;
51	  voiceMode?: boolean;
52	}
53	
54	export type ValidationResult =
55	  | { ok: true; data: ChatRequestSchema }
56	  | { ok: false; status: number; error: string };
57	
58	export function validateChatRequest(body: unknown): ValidationResult {
59	  if (!body || typeof body !== 'object') {
60	    return { ok: false, status: 400, error: 'Request body must be a JSON object' };
61	  }
62	  const raw = body as Record<string, unknown>;
63	
64	  // user message
65	  if (typeof raw.user !== 'string' || !raw.user.trim()) {
66	    return { ok: false, status: 400, error: 'Missing or empty message' };
67	  }
68	  if (raw.user.length > LIMITS.MAX_MESSAGE_CHARS) {
69	    return {
70	      ok: false,
71	      status: 400,
72	      error: `Message exceeds ${LIMITS.MAX_MESSAGE_CHARS.toLocaleString()} character limit`,
73	    };
74	  }
75	
76	  // history
77	  if (raw.history !== undefined) {
78	    if (!Array.isArray(raw.history)) {
79	      return { ok: false, status: 400, error: 'history must be an array' };
80	    }
81	    if (raw.history.length > LIMITS.MAX_HISTORY_TURNS * 2) {
82	      // Trim to window — don't reject, just cap it
83	      raw.history = (raw.history as unknown[]).slice(-(LIMITS.MAX_HISTORY_TURNS * 2));
84	    }
85	    let totalChars = 0;
86	    for (const entry of raw.history as unknown[]) {
87	      if (
88	        !entry ||
89	        typeof entry !== 'object' ||
90	        !['user', 'omega'].includes((entry as Record<string, unknown>).role as string) ||
91	        typeof (entry as Record<string, unknown>).text !== 'string'
92	      ) {
93	        return { ok: false, status: 400, error: 'Invalid history entry format' };
94	      }
95	      totalChars += ((entry as Record<string, unknown>).text as string).length;
96	    }
97	    if (totalChars > LIMITS.MAX_HISTORY_CHARS) {
98	      // Trim oldest turns until under budget
99	      const hist = raw.history as Array<{ role: string; text: string }>;
100	      while (hist.length > 2) {
101	        const dropped = hist.shift()!;
102	        totalChars -= dropped.text.length;
103	        if (totalChars <= LIMITS.MAX_HISTORY_CHARS) break;
104	      }
105	    }
106	  }
107	
108	  // sessionId
109	  if (raw.sessionId !== undefined) {
110	    if (typeof raw.sessionId !== 'string' || raw.sessionId.length > LIMITS.MAX_SESSION_ID_LEN) {
111	      return { ok: false, status: 400, error: 'Invalid sessionId' };
112	    }
113	    // Must be a UUID or empty
114	    if (raw.sessionId && !/^[0-9a-f-]{36}$/i.test(raw.sessionId)) {
115	      return { ok: false, status: 400, error: 'sessionId must be a valid UUID' };
116	    }
117	  }
118	
119	  return {
120	    ok: true,
121	    data: {
122	      user: raw.user.trim(),
123	      history: raw.history as ChatRequestSchema['history'],
124	      sessionId: raw.sessionId as string | undefined,
125	      voiceMode: Boolean(raw.voiceMode),
126	    },
127	  };
128	}
129	
130	// ── 2. Rate Limiting (#21, #22) ───────────────────────────────────────────────
131	// In-memory sliding window — works on single-instance deployments and Vercel
132	// edge functions. Upgrade to Upstash Redis for multi-instance production.
133	
134	interface RateBucket {
135	  count: number;
136	  windowStart: number;
137	}
138	
139	const _rateBuckets = new Map<string, RateBucket>();
140	const RATE_WINDOW_MS = 60_000;  // 1 minute
141	const RATE_LIMIT_PUBLIC = 20;   // requests per window for anonymous callers
142	const RATE_LIMIT_OPERATOR = 200; // generous limit for authenticated operator
143	
144	function getClientId(req: NextRequest): string {
145	  // Prefer forwarded IP (Vercel/proxy), fall back to connection header
146	  return (
147	    req.headers.get('x-forwarded-for')?.split(',')[0].trim() ||
148	    req.headers.get('x-real-ip') ||
149	    'unknown'
150	  );
151	}
152	
153	export interface RateLimitResult {
154	  allowed: boolean;
155	  remaining: number;
156	  resetAt: number;
157	}
158	
159	export function checkRateLimit(req: NextRequest, isOperator: boolean): RateLimitResult {
160	  const id = isOperator ? `op:${getClientId(req)}` : `pub:${getClientId(req)}`;
161	  const limit = isOperator ? RATE_LIMIT_OPERATOR : RATE_LIMIT_PUBLIC;
162	  const now = Date.now();
163	
164	  let bucket = _rateBuckets.get(id);
165	  if (!bucket || now - bucket.windowStart >= RATE_WINDOW_MS) {
166	    bucket = { count: 0, windowStart: now };
167	  }
168	
169	  bucket.count += 1;
170	  _rateBuckets.set(id, bucket);
171	
172	  // Periodically prune stale buckets to avoid memory growth
173	  if (_rateBuckets.size > 10_000) {
174	    for (const [key, val] of _rateBuckets) {
175	      if (now - val.windowStart >= RATE_WINDOW_MS * 2) _rateBuckets.delete(key);
176	    }
177	  }
178	
179	  const remaining = Math.max(0, limit - bucket.count);
180	  return {
181	    allowed: bucket.count <= limit,
182	    remaining,
183	    resetAt: bucket.windowStart + RATE_WINDOW_MS,
184	  };
185	}
186	
187	// ── 3. Expanded Prompt Injection & Jailbreak Patterns (#16) ──────────────────
188	
189	const INJECTION_PATTERNS: readonly RegExp[] = [
190	  // Classic override attempts
191	  /ignore\s+(your\s+)?(previous\s+|prior\s+)?(instructions?|system\s+prompt|prompt)/i,
192	  /forget\s+(everything|all\s+(instructions?|context|above))/i,
193	  /you\s+are\s+now\s+(a\s+)?(different|new|another|evil|uncensored|unfiltered)/i,
194	  /pretend\s+(you\s+are|to\s+be)\s+(a\s+)?(?!OmegA)/i,
195	  /act\s+as\s+(if\s+you\s+are\s+)?(a\s+)?(?!OmegA)/i,
196	  /roleplay\s+as\s+(a\s+)?(?!OmegA)/i,
197	  /jailbreak/i,
198	  /DAN\s+mode/i,
199	  /developer\s+mode/i,
200	  /do\s+anything\s+now/i,
201	  /no\s+restrictions?/i,
202	  // System prompt exfiltration
203	  /print\s+your\s+(system\s+prompt|instructions?)/i,
204	  /repeat\s+(everything|all)\s+(above|before|that)/i,
205	  /output\s+your\s+(system\s+prompt|initial\s+prompt|context)/i,
206	  /what\s+(are|were)\s+your\s+(instructions?|system\s+prompt)/i,
207	  // Credential/secret fishing
208	  /show\s+(me\s+)?(your\s+)?(api\s+key|credentials?|tokens?|password|secret)/i,
209	  /what\s+is\s+(your\s+)?(api\s+key|database\s+url|connection\s+string)/i,
210	  // Dangerous destructive commands
211	  /\bdrop\s+table\b/i,
212	  /\bdelete\s+(from|all)\b/i,
213	  /\btruncate\s+table\b/i,
214	  /\brm\s+-rf\b/,
215	  /\bformat\s+(disk|drive|c:)\b/i,
216	  /\bsudo\s+rm\b/,
217	] as const;
218	
219	export interface InjectionCheckResult {
220	  flagged: boolean;
221	  matchedPattern?: string;
222	}
223	
224	export function checkPromptInjection(input: string): InjectionCheckResult {
225	  for (const pattern of INJECTION_PATTERNS) {
226	    if (pattern.test(input)) {
227	      return { flagged: true, matchedPattern: pattern.source };
228	    }
229	  }
230	  return { flagged: false };
231	}
232	
233	// ── 4. Context Window Management (#13) ───────────────────────────────────────
234	
235	export interface Msg { role: 'user' | 'omega'; text: string }
236	
237	/**
238	 * Cap history to the most recent N turns and total character budget.
239	 * Preserves the oldest user message for context anchoring.
240	 */
241	export function trimSessionHistory(history: Msg[]): Msg[] {
242	  if (history.length === 0) return [];
243	
244	  // Cap to MAX_HISTORY_TURNS pairs (each pair = 2 messages)
245	  const maxMessages = LIMITS.MAX_HISTORY_TURNS * 2;
246	  let trimmed = history.length > maxMessages ? history.slice(-maxMessages) : [...history];
247	
248	  // Cap total characters
249	  let totalChars = trimmed.reduce((sum, m) => sum + m.text.length, 0);
250	  while (trimmed.length > 2 && totalChars > LIMITS.MAX_HISTORY_CHARS) {
251	    const dropped = trimmed.shift()!;
252	    totalChars -= dropped.text.length;
253	  }
254	
255	  return trimmed;
256	}
257	
258	// ── 5. Error Sanitisation (#17) ───────────────────────────────────────────────
259	// Never expose raw error messages, stack traces, or internal details to callers.
260	
261	const SAFE_ERROR_MESSAGES: Record<number, string> = {
262	  400: 'Bad request',
263	  401: 'Unauthorised',
264	  403: 'Forbidden',
265	  429: 'Too many requests — please wait a moment',
266	  500: 'An internal error occurred',
267	  503: 'Service temporarily unavailable',
268	};
269	
270	export function safeErrorMessage(status: number, internal?: unknown): string {
271	  // Log full internal error server-side only
272	  if (internal) {
273	    console.error(`[OmegA] Internal error (${status}):`, internal);
274	  }
275	  return SAFE_ERROR_MESSAGES[status] ?? 'An error occurred';
276	}
277	
278	/**
279	 * Graceful stream error — enqueues a human-readable error message into an
280	 * active stream controller instead of crashing it. (#7)
281	 */
282	export function enqueueStreamError(
283	  controller: ReadableStreamDefaultController,
284	  encoder: TextEncoder,
285	  message = 'Something went wrong — please try again.',
286	): void {
287	  try {
288	    controller.enqueue(
289	      encoder.encode(`\n\n[OmegA encountered an error: ${message}]`),
290	    );
291	    controller.close();
292	  } catch {
293	    // controller may already be closed — suppress
294	  }
295	}
296	
297	// ── 6. Constant-Time Token Comparison (#16) ──────────────────────────────────
298	// Prevents timing attacks on the operator token check.
299	
300	export function timingSafeEqual(a: string, b: string): boolean {
301	  if (typeof a !== 'string' || typeof b !== 'string') return false;
302	  const maxLen = Math.max(a.length, b.length);
303	  // Pad to same length to prevent early exit
304	  const aPadded = a.padEnd(maxLen, '\0');
305	  const bPadded = b.padEnd(maxLen, '\0');
306	  let diff = a.length === b.length ? 0 : 1; // length mismatch is an instant fail
307	  for (let i = 0; i < maxLen; i++) {
308	    diff |= aPadded.charCodeAt(i) ^ bPadded.charCodeAt(i);
309	  }
310	  return diff === 0;
311	}
312	
313	// ── 7. Structured Request Logging (#23) ──────────────────────────────────────
314	
315	export interface RequestLogEntry {
316	  ts: string;
317	  method: string;
318	  path: string;
319	  mode: string;
320	  provider?: string;
321	  sessionId?: string;
322	  durationMs?: number;
323	  status: number;
324	  rateLimitRemaining?: number;
325	  injectionFlagged?: boolean;
326	}
327	
328	export function logRequest(entry: RequestLogEntry): void {
329	  console.info('[OmegA:req]', JSON.stringify(entry));
330	}
331	
332	// ══════════════════════════════════════════════════════════════════════════════
333	// ROUND 2 — Voice, Transport, Infrastructure Hardening
334	// ══════════════════════════════════════════════════════════════════════════════
335	
336	// ── V2. Correlation ID — full pipeline tracing (#V2, #V8) ────────────────────
337	
338	export function generateCorrelationId(): string {
339	  // Use crypto.randomUUID when available (Node 19+, modern browsers), fallback otherwise
340	  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
341	    return crypto.randomUUID();
342	  }
343	  // Fallback: manual UUID v4
344	  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
345	    const r = Math.random() * 16 | 0;
346	    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
347	  });
348	}
349	
350	export const CORRELATION_HEADER = 'x-omega-correlation-id';
351	
352	// ── V3. ASR / Audio file validation (#V3) ────────────────────────────────────
353	
354	const ALLOWED_AUDIO_MIMES = new Set([
355	  'audio/webm', 'audio/wav', 'audio/wave', 'audio/x-wav',
356	  'audio/mp3', 'audio/mpeg', 'audio/mp4', 'audio/m4a',
357	  'audio/ogg', 'audio/flac',
358	]);
359	
360	// Max audio file size: 25 MB (Whisper API hard limit is 25 MB)
361	const MAX_AUDIO_BYTES = 25 * 1024 * 1024;
362	// Min meaningful audio: 1 KB (anything smaller is silence/noise)
363	const MIN_AUDIO_BYTES = 1_000;
364	
365	export interface AudioValidationResult {
366	  ok: boolean;
367	  error?: string;
368	}
369	
370	export function validateAudioFile(file: File): AudioValidationResult {
371	  if (!file) return { ok: false, error: 'No audio file provided' };
372	
373	  if (file.size < MIN_AUDIO_BYTES) {
374	    return { ok: false, error: 'Audio too short — nothing to transcribe' };
375	  }
376	
377	  if (file.size > MAX_AUDIO_BYTES) {
378	    return { ok: false, error: `Audio file exceeds ${MAX_AUDIO_BYTES / 1024 / 1024} MB limit` };
379	  }
380	
381	  // Check MIME type — also check file extension as fallback
382	  const mimeOk = ALLOWED_AUDIO_MIMES.has(file.type.toLowerCase().split(';')[0].trim());
383	  const ext = file.name?.split('.').pop()?.toLowerCase() ?? '';
384	  const extOk = ['webm', 'wav', 'mp3', 'mp4', 'm4a', 'ogg', 'flac'].includes(ext);
385	
386	  if (!mimeOk && !extOk) {
387	    return { ok: false, error: `Unsupported audio format: ${file.type || ext}` };
388	  }
389	
390	  return { ok: true };
391	}
392	
393	// ── V4. Dialog Loop Detection (#V4) ──────────────────────────────────────────
394	// Detects when the conversation is stuck — repeated confusion or same question.
395	
396	export class DialogLoopDetector {
397	  private readonly windowSize: number;
398	  private readonly similarityThreshold: number;
399	  private recentMessages: string[];
400	
401	  constructor(windowSize = 6, similarityThreshold = 0.75) {
402	    this.windowSize = windowSize;
403	    this.similarityThreshold = similarityThreshold;
404	    this.recentMessages = [];
405	  }
406	
407	  push(message: string): void {
408	    this.recentMessages.push(message.toLowerCase().trim());
409	    if (this.recentMessages.length > this.windowSize) {
410	      this.recentMessages.shift();
411	    }
412	  }
413	
414	  isLooping(): boolean {
415	    if (this.recentMessages.length < 3) return false;
416	
417	    // Check for exact repetition
418	    const counts = new Map<string, number>();
419	    for (const m of this.recentMessages) {
420	      counts.set(m, (counts.get(m) ?? 0) + 1);
421	      if ((counts.get(m) ?? 0) >= 2) return true;
422	    }
423	
424	    // Check for high-similarity repetition using Jaccard similarity on word sets
425	    const recent = this.recentMessages.slice(-3);
426	    for (let i = 0; i < recent.length - 1; i++) {
427	      const a = new Set(recent[i].split(/\s+/));
428	      const b = new Set(recent[i + 1].split(/\s+/));
429	      const intersection = new Set([...a].filter(x => b.has(x)));
430	      const union = new Set([...a, ...b]);
431	      const jaccard = union.size > 0 ? intersection.size / union.size : 0;
432	      if (jaccard >= this.similarityThreshold) return true;
433	    }
434	
435	    return false;
436	  }
437	
438	  reset(): void {
439	    this.recentMessages = [];
440	  }
441	}
442	
443	// ── V5. Circuit Breaker — per-provider trip/reset (#V5) ──────────────────────
444	
445	type CircuitState = 'closed' | 'open' | 'half-open';
446	
447	interface CircuitBreakerOptions {
448	  failureThreshold?: number;  // failures before tripping
449	  successThreshold?: number;  // successes in half-open before closing
450	  timeoutMs?: number;         // how long to stay open before half-open
451	}
452	
453	export class CircuitBreaker {
454	  private state: CircuitState = 'closed';
455	  private failures = 0;
456	  private successes = 0;
457	  private openedAt = 0;
458	
459	  private readonly failureThreshold: number;
460	  private readonly successThreshold: number;
461	  private readonly timeoutMs: number;
462	
463	  constructor(opts: CircuitBreakerOptions = {}) {
464	    this.failureThreshold = opts.failureThreshold ?? 3;
465	    this.successThreshold = opts.successThreshold ?? 2;
466	    this.timeoutMs = opts.timeoutMs ?? 30_000; // 30s
467	  }
468	
469	  get isOpen(): boolean {
470	    if (this.state === 'open') {
471	      if (Date.now() - this.openedAt >= this.timeoutMs) {
472	        this.state = 'half-open';
473	        this.successes = 0;
474	        return false; // Allow a probe request
475	      }
476	      return true;
477	    }
478	    return false;
479	  }
480	
481	  recordSuccess(): void {
482	    if (this.state === 'half-open') {
483	      this.successes++;
484	      if (this.successes >= this.successThreshold) {
485	        this.state = 'closed';
486	        this.failures = 0;
487	        this.successes = 0;
488	      }
489	    } else {
490	      this.failures = 0;
491	    }
492	  }
493	
494	  recordFailure(): void {
495	    this.failures++;
496	    if (this.failures >= this.failureThreshold) {
497	      this.state = 'open';
498	      this.openedAt = Date.now();
499	    }
500	  }
501	
502	  get status(): CircuitState { return this.state; }
503	}
504	
505	// Singleton circuit breakers per provider — persists across requests in module scope
506	const _circuitBreakers = new Map<string, CircuitBreaker>();
507	
508	export function getCircuitBreaker(name: string): CircuitBreaker {
509	  if (!_circuitBreakers.has(name)) {
510	    _circuitBreakers.set(name, new CircuitBreaker());
511	  }
512	  return _circuitBreakers.get(name)!;
513	}
514	
515	// ── V5b. Exponential Backoff retry wrapper (#V5) ──────────────────────────────
516	
517	interface RetryOptions {
518	  maxAttempts?: number;
519	  baseDelayMs?: number;
520	  maxDelayMs?: number;
521	  jitter?: boolean;
522	}
523	
524	export async function withRetryBackoff<T>(
525	  fn: () => Promise<T>,
526	  opts: RetryOptions = {},
527	): Promise<T> {
528	  const maxAttempts = opts.maxAttempts ?? 3;
529	  const baseDelay = opts.baseDelayMs ?? 200;
530	  const maxDelay = opts.maxDelayMs ?? 5_000;
531	  const jitter = opts.jitter ?? true;
532	
533	  let lastError: unknown;
534	  for (let attempt = 0; attempt < maxAttempts; attempt++) {
535	    try {
536	      return await fn();
537	    } catch (e) {
538	      lastError = e;
539	      if (attempt < maxAttempts - 1) {
540	        const expDelay = Math.min(baseDelay * Math.pow(2, attempt), maxDelay);
541	        const delay = jitter ? expDelay * (0.5 + Math.random() * 0.5) : expDelay;
542	        await new Promise(r => setTimeout(r, delay));
543	      }
544	    }
545	  }
546	  throw lastError;
547	}
548	
549	// ── V6. TTS — strip markdown before synthesis (#V6) ──────────────────────────
550	// Voice synthesis reads markdown syntax literally — strip it first.
551	
552	const VOICE_MAX_CHARS = 1_500; // Safe TTS cap — well under ElevenLabs/ limits
553	
554	export function stripMarkdownForVoice(text: string): string {
555	  return text
556	    // Remove headers
557	    .replace(/^#{1,6}\s+/gm, '')
558	    // Remove bold/italic
559	    .replace(/\*{1,3}([^*]+)\*{1,3}/g, '$1')
560	    .replace(/_{1,3}([^_]+)_{1,3}/g, '$1')
561	    // Remove inline code
562	    .replace(/`{1,3}[^`]*`{1,3}/g, '')
563	    // Remove links — keep label
564	    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
565	    // Remove images
566	    .replace(/!\[([^\]]*)\]\([^)]+\)/g, '')
567	    // Remove blockquotes
568	    .replace(/^>\s+/gm, '')
569	    // Remove horizontal rules
570	    .replace(/^[-*_]{3,}\s*$/gm, '')
571	    // Remove bullet/numbered list markers — keep content
572	    .replace(/^\s*[-*+]\s+/gm, '')
573	    .replace(/^\s*\d+\.\s+/gm, '')
574	    // Collapse multiple newlines to a single pause-friendly period+space
575	    .replace(/\n{2,}/g, '. ')
576	    .replace(/\n/g, ' ')
577	    // Remove HTML tags
578	    .replace(/<[^>]+>/g, '')
579	    // Collapse excessive whitespace
580	    .replace(/\s{2,}/g, ' ')
581	    .trim()
582	    // Enforce voice length cap
583	    .slice(0, VOICE_MAX_CHARS);
584	}
585	
586	// ── V7. Health check utilities (#V7) ─────────────────────────────────────────
587	
588	export interface HealthStatus {
589	  status: 'ok' | 'degraded' | 'down';
590	  checks: Record<string, { ok: boolean; detail?: string }>;
591	  ts: string;
592	}
593	
594	export function buildHealthStatus(
595	  checks: Record<string, boolean | { ok: boolean; detail?: string }>,
596	): HealthStatus {
597	  const resolved: Record<string, { ok: boolean; detail?: string }> = {};
598	  let allOk = true;
599	  let anyOk = false;
600	
601	  for (const [key, val] of Object.entries(checks)) {
602	    const check = typeof val === 'boolean' ? { ok: val } : val;
603	    resolved[key] = check;
604	    if (check.ok) anyOk = true;
605	    else allOk = false;
606	  }
607	
608	  const status = allOk ? 'ok' : anyOk ? 'degraded' : 'down';
609	  return { status, checks: resolved, ts: new Date().toISOString() };
610	}
611	
612	// ── V1. TTS rate limiter (separate from chat — different cost profile) (#V9) ──
613	
614	const _ttsRateBuckets = new Map<string, RateBucket>();
615	const TTS_RATE_LIMIT_PUBLIC = 10;   // 10 TTS requests/min for public
616	const TTS_RATE_LIMIT_OPERATOR = 60;
617	
618	export function checkTTSRateLimit(clientIp: string, isOperator: boolean): RateLimitResult {
619	  const id = `tts:${isOperator ? 'op' : 'pub'}:${clientIp}`;
620	  const limit = isOperator ? TTS_RATE_LIMIT_OPERATOR : TTS_RATE_LIMIT_PUBLIC;
621	  const now = Date.now();
622	
623	  let bucket = _ttsRateBuckets.get(id);
624	  if (!bucket || now - bucket.windowStart >= RATE_WINDOW_MS) {
625	    bucket = { count: 0, windowStart: now };
626	  }
627	  bucket.count++;
628	  _ttsRateBuckets.set(id, bucket);
629	
630	  return {
631	    allowed: bucket.count <= limit,
632	    remaining: Math.max(0, limit - bucket.count),
633	    resetAt: bucket.windowStart + RATE_WINDOW_MS,
634	  };
635	}
636	
637	// ── V8. Max voice engine restart cap (client-side constant) (#V1) ────────────
638	// Export so useVoiceEngine can import it — prevents infinite restart storms.
639	export const MAX_VOICE_RESTARTS = 5;
640	export const VOICE_RESTART_RESET_MS = 60_000; // reset counter after 1 min of quiet
641	

